instruction:
Declare functions BEFORE `main()` or provide a **forward declaration**:

```cpp
returnType functionName(paramType param) {
    return value;
}
```

`void` = returns nothing. Run this.

starter:
#include <iostream>
using namespace std;

string greet(string name) {
    return "Hello, " + name + "!";
}

void printSeparator() {
    cout << "----------" << endl;
}

int main() {
    cout << greet("Alice") << endl;
    cout << greet("Bob")   << endl;
    printSeparator();
    cout << greet("Carol") << endl;
    return 0;
}

#include <iostream>
using namespace std;

void tryToDouble(int n) {
    n = n * 2;  // only changes the LOCAL copy
    cout << "Inside: " << n << endl;
}

int main() {
    int x = 10;
    cout << "Before: " << x << endl;
    tryToDouble(x);
    cout << "After: "  << x << endl;  // still 10!
    return 0;
}

#include <iostream>
#include <string>
using namespace std;

void doubleIt(int& n) {
    n *= 2;  // modifies the original
}

void swap(int& a, int& b) {
    int temp = a;
    a = b;
    b = temp;
}

// const& for efficiency without modification:
void printName(const string& name) {
    cout << "Name: " << name << endl;
}

int main() {
    int x = 10;
    doubleIt(x);
    cout << x << endl;  // 20!

    int a = 3, b = 7;
    swap(a, b);
    cout << a << " " << b << endl;  // 7 3

    printName("Alice");
    return 0;
}

instruction:
Parameters can have default values — used when the caller doesn't provide them:

```cpp
void greet(string name, string title = "Mr.") {
    cout << title << " " << name << endl;
}
greet("Smith");         // Mr. Smith
greet("Smith", "Dr."); // Dr. Smith
```

Defaults must come at the END of the parameter list.

