#include <iostream>
#include <string>
using namespace std;

double power(double base, int exp = 2) {
    double result = 1;
    for (int i = 0; i < exp; i++) result *= base;
    return result;
}

void log(string message, string level = "INFO") {
    cout << "[" << level << "] " << message << endl;
}

int main() {
    cout << power(5)    << endl;  // 5^2
    cout << power(2, 8) << endl;  // 2^8
    cout << power(3, 3) << endl;  // 3^3

    log("Server started");
    log("Connection failed", "ERROR");
    log("Low memory", "WARN");

    return 0;
}

#include <iostream>
#include <string>
using namespace std;

int add(int a, int b) {
    return a + b;
}

double add(double a, double b) {
    return a + b;
}

string add(string a, string b) {
    return a + b;
}

int add(int a, int b, int c) {
    return a + b + c;
}

int main() {
    cout << add(3, 4)          << endl;  // int version
    cout << add(3.5, 4.5)      << endl;  // double version
    cout << add("Hello, ", "World") << endl; // string version
    cout << add(1, 2, 3)       << endl;  // three-arg version
    return 0;
}

#include <iostream>
using namespace std;

long long factorial(int n) {
    if (n <= 1) return 1;           // base case
    return n * factorial(n - 1);    // recursive case
}

int fibonacci(int n) {
    if (n <= 1) return n;
    return fibonacci(n-1) + fibonacci(n-2);
}

int main() {
    cout << factorial(5) << endl;
    cout << factorial(10) << endl;

    for (int i = 0; i <= 8; i++) {
        cout << fibonacci(i) << " ";
    }
    cout << endl;

    return 0;
}
